import { useState } from "react";

import {
  Container,
  Box,
  TextField,
  Button,
  Typography,
  Paper,
} from "@mui/material";

function App() {
  const [id, setId] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");

  const handleLogin = async () => {
    try {
      const response = await fetch("http://127.0.0.1:5000/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          id,
          password,
        }),
      });

      const data = await response.json();

      if (data.success) {
        setMessage("로그인 성공!");
      } else {
        setMessage(data.message);
      }
    } catch (error) {
      setMessage("서버 오류");
    }
  };

  return (
    <Box
      sx={{
        minHeight: "100vh",

        display: "flex",
        justifyContent: "center",
        alignItems: "center",

        background: `
          radial-gradient(circle at top left, #ff4d4d 0%, transparent 30%),
          radial-gradient(circle at bottom right, #990000 0%, transparent 35%),
          linear-gradient(135deg, #1a0000, #330000, #120000)
        `,

        overflow: "hidden",
        padding: 2,
      }}
    >
      <Container
        maxWidth="xs"
        sx={{
          display: "flex",
          justifyContent: "center",
        }}
      >
        <Paper
          elevation={10}
          sx={{
            width: "100%",

            minHeight: {
              xs: "500px",
              sm: "600px",
            },

            borderRadius: "28px",

            padding: {
              xs: 3,
              sm: 5,
            },

            display: "flex",
            flexDirection: "column",
            justifyContent: "center",

            backdropFilter: "blur(10px)",

            background: "rgba(255,255,255,0.08)",

            border: "1px solid rgba(255,255,255,0.15)",

            boxShadow: `
              0 0 30px rgba(255,0,0,0.35),
              0 0 80px rgba(255,0,0,0.15)
            `,
          }}
        >
          <Typography
            variant="h4"
            align="center"
            sx={{
              color: "white",
              fontWeight: "bold",
              marginBottom: 5,
              letterSpacing: 2,
            }}
          >
            LOGIN
          </Typography>

          <TextField
            label="ID"
            variant="outlined"
            fullWidth
            margin="normal"
            value={id}
            onChange={(e) => setId(e.target.value)}
            InputLabelProps={{
              style: { color: "#ddd" },
            }}
            sx={{
              input: { color: "white" },

              "& .MuiOutlinedInput-root": {
                "& fieldset": {
                  borderColor: "rgba(255,255,255,0.3)",
                },
                "&:hover fieldset": {
                  borderColor: "#ff4d4d",
                },
                "&.Mui-focused fieldset": {
                  borderColor: "#ff1a1a",
                },
              },
            }}
          />

          <TextField
            label="Password"
            type="password"
            variant="outlined"
            fullWidth
            margin="normal"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            InputLabelProps={{
              style: { color: "#ddd" },
            }}
            sx={{
              input: { color: "white" },

              "& .MuiOutlinedInput-root": {
                "& fieldset": {
                  borderColor: "rgba(255,255,255,0.3)",
                },
                "&:hover fieldset": {
                  borderColor: "#ff4d4d",
                },
                "&.Mui-focused fieldset": {
                  borderColor: "#ff1a1a",
                },
              },
            }}
          />

          <Button
            fullWidth
            variant="contained"
            onClick={handleLogin}
            sx={{
              marginTop: 4,
              padding: 1.5,

              borderRadius: "14px",

              fontWeight: "bold",

              background:
                "linear-gradient(45deg, #ff1a1a, #cc0000)",

              boxShadow: `
                0 0 20px rgba(255,0,0,0.5)
              `,

              "&:hover": {
                background:
                  "linear-gradient(45deg, #ff3333, #ff0000)",
              },
            }}
          >
            로그인
          </Button>

          <Typography
            align="center"
            sx={{
              color: "#ffb3b3",
              marginTop: 3,
            }}
          >
            {message}
          </Typography>
        </Paper>
      </Container>
    </Box>
  );
}

export default App;
